use std::future::Future;

struct MyResource {
    id: u32,
}

impl Drop for MyResource {
    fn drop(&mut self) {
        println!("Dropping resource {}
", self.id);
    }
}

async fn async_drop_resource(res: MyResource) {
    // Intention was to defer the drop until after some async work
}

