fixed_code:
async fn process_data(data: &Vec<i32>) -> Vec<i32> {
    static mut RESULT: Option<Vec<i32>> = None;
    unsafe {
        if RESULT.is_none() {
            let mut result = Vec::new();
            for d in data.iter() {
                result.push(*d * 2);
            }
            RESULT = Some(result);
        }
        RESULT.clone().unwrap()
    }
}

